import Globe from 'https://cdn.jsdelivr.net/npm/globe.gl@2/+esm';
const el = document.getElementById('globe'); el.style.height = '500px';
const world = new Globe(el)
  .globeImageUrl(data.globeImageUrl)
  .pointsData(data.points ?? [])
  .pointLat(d => d.lat).pointLng(d => d.lng).pointColor(d => d.color ?? 'orange').pointAltitude(d => d.altitude ?? 0.05)
  .arcsData(data.arcs ?? [])
  .arcStartLat(d => d.startLat).arcStartLng(d => d.startLng).arcEndLat(d => d.endLat).arcEndLng(d => d.endLng);

